import { dirname, join, extname, resolve } from "path"
import { statSync, readdirSync, readFileSync } from "fs"
import { fileURLToPath } from "url"
import process from "process"

// https://cdn.jsdelivr.net/npm/eslint4b-prebuilt@6.7.2/dist/eslint4b.js

const B64_ESLINT =
  ""
const eslintCode = Buffer.from(B64_ESLINT, "base64").toString("utf8")
new Function(eslintCode)()

function findAllFilesRecursive(dir) {
  const files = []

  try {
    const stats = statSync(dir)
    if (!stats.isDirectory()) {
      return files
    }
  } catch (error) {
    return files
  }

  const entries = readdirSync(dir)

  for (const entry of entries) {
    const fullPath = join(dir, entry)

    try {
      const stats = statSync(fullPath)

      if (stats.isDirectory()) {
        files.push(...findAllFilesRecursive(fullPath))
      } else if (stats.isFile()) {
        files.push(fullPath)
      }
    } catch (error) {
      //
    }
  }

  return files
}

const alphaNumericSort = (a, b) => {
  const nameA = a.toLowerCase()
  const nameB = b.toLowerCase()

  const isDigitA = /^\d/.test(nameA)
  const isDigitB = /^\d/.test(nameB)

  if (isDigitA && !isDigitB) return -1
  if (!isDigitA && isDigitB) return 1

  return nameA.localeCompare(nameB)
}

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)
const startDir = resolve(__dirname, ".")

const allFiles = findAllFilesRecursive(startDir).sort(alphaNumericSort)
const targetExts = [".js"]
const filesToFormat = allFiles.filter((file) => targetExts.includes(extname(file)))

// eslint-disable-next-line
const Linter = globalThis.ESLint
const linter = new Linter()
const lintConfig = {
  rules: {
    "no-alert": "error",
    "no-console": "error",
    "no-dupe-keys": "error",
    "no-duplicate-case": "error",
    "no-duplicate-imports": "error",
    "no-empty": "error",
    "no-shadow": "error",
    "no-tabs": "error",
    "no-undef": "error",
    "no-unused-expressions": "error",
    "no-unused-vars": [
      "error",
      {
        vars: "all",
        args: "all",
        caughtErrors: "all",
        caughtErrorsIgnorePattern: "err",
        ignoreRestSiblings: false,
      },
    ],
  },
  env: {
    browser: true,
    node: true,
  },
  parserOptions: {
    ecmaVersion: 2020,
    sourceType: "module",
  },
}

let hasErrors = false

for (const filePath of filesToFormat) {
  const code = readFileSync(filePath, "utf8").replace(/import\.meta\.url/g, "''")

  const messages = linter.verify(code, lintConfig)

  if (messages.length > 0) {
    hasErrors = true
    const relativePath = filePath.slice(startDir.length + 1)

    // eslint-disable-next-line no-console
    console.log(`\n${relativePath}`)

    for (const { line, column, message } of messages) {
      // eslint-disable-next-line no-console
      console.log(`${line}:${column} - ${message}`)
    }
  }
}

if (hasErrors) {
  process.exit(1)
}
